mapper.select:
SELECT task_id AS taskId, COUNT(student_id) AS partakeCount FROM student_usually_score WHERE deleted = 0 AND task_id IN
#{item}
GROUP BY task_id

SELECT score.id AS id, stu.id AS studentId, stu.seat_no AS seatNo, stu.chinese_name AS chineseName, stu.english_name AS englishName, stu.display_name_type AS displayNameType, stu.student_no AS studentNo, task.subject_id AS subjectId, subject.subject_name AS subjectName, task.id AS taskId, task.name AS taskName, task.test_date AS testDate, stu.student_no AS studentNo, sem.name AS periodName, score.score AS score, task.type_id AS typeId FROM student_usually_score score LEFT JOIN student_usually_task task ON task.id = score.task_id LEFT JOIN subject_rel srl ON srl.id = task.subject_id LEFT JOIN subject subject ON subject.id = srl.subject_id LEFT JOIN sys_semester sem ON sem.id = task.period_id LEFT JOIN student_info stu ON stu.id = score.student_id WHERE score.deleted = 0 AND task.deleted = 0
AND score.student_id = #{studentId}
AND score.task_id IN
#{item}

SELECT score.student_id AS studentId, task.period_id AS periodId, task.subject_id AS subjectId, score.score AS score, task.type_id AS typeId FROM student_usually_score score LEFT JOIN student_usually_task task ON task.id = score.task_id WHERE task.class_id = #{classId}
AND task.period_id = #{periodId}
AND score.deleted = 0 AND task.deleted = 0 ORDER BY score.student_id ASC

SELECT score.id AS id, score.student_id AS studentId, task.test_date AS testTime, task.subject_id AS subjectId, s.subject_name AS subjectName, sr.subject_type AS subjectType, score.score AS score, task.type_id AS testType, ty.type_name AS testTypeName FROM student_usually_score score LEFT JOIN student_usually_task task ON task.id = score.task_id AND task.deleted = 0 LEFT JOIN subject_rel sr ON sr.id = task.subject_id AND sr.deleted = 0 LEFT JOIN `subject` s ON s.id = sr.subject_id AND s.deleted = 0 LEFT JOIN `student_usually_type` ty on ty.id = task.type_id WHERE score.deleted = 0 AND score.student_id = ${reqModel.studentId}
AND task.period_id = ${reqModel.semesterId}
AND task.test_date >= #{reqModel.startTime}
AND task.test_date <= #{reqModel.endTime}
AND sr.id = ${reqModel.subjectId}
AND sr.subject_type = ${reqModel.subjectType}
AND task.type_id = ${reqModel.testType}
ORDER BY task.test_date DESC
